!function(){const t=document.createElement("style");t.textContent="\n    .toast {\n      position: fixed;\n      bottom: 32px;\n      left: 50%;\n      transform: translateX(-50%);\n      min-width: 220px;\n      max-width: 90vw;\n      background: #2e3657;\n      color: #fff;\n      padding: 1em 2em;\n      border-radius: 8px;\n      box-shadow: 0 2px 16px rgba(30,40,90,0.15);\n      font-size: 1.1em;\n      z-index: 9999;\n      opacity: 0;\n      pointer-events: none;\n      transition: opacity 0.3s, bottom 0.3s;\n    }\n    .toast.show {\n      opacity: 1;\n      pointer-events: auto;\n      bottom: 48px;\n    }\n    .toast.error { background: #e53e3e; }\n    .toast.success { background: #22c55e; }\n    .toast.info { background: #2563eb; }\n  ",document.head.appendChild(t),window.showToast=function(t,n="info"){let o=document.querySelector(".toast");o||(o=document.createElement("div"),o.className="toast",document.body.appendChild(o)),o.textContent=t,o.className="toast "+n,setTimeout(()=>o.classList.add("show"),10),setTimeout(()=>{o.classList.remove("show")},3200)}}();